351:     /**
352:      * Begin connecting to the given node, return true if we are already connected and ready to send to that node.
353:      *
354:      * @param node The node to check
355:      * @param now The current timestamp
356:      * @return True if we are ready to send to the given node
357:      */
358:     @Override
359:     public boolean ready(Node node, long now) {
360:         if (node.isEmpty())
361:             throw new IllegalArgumentException("Cannot connect to empty node " + node);
362: 
363:         if (isReady(node, now))
364:             return true;
365: 
366:         if (connectionStates.canConnect(node.idString(), now))
367:             // if we are interested in sending to a node and we don't have a connection to it, initiate one
368:             initiateConnect(node, now);
369: 
370:         return false;
371:     }
