380:      * Any pending ClientRequests for this connection will receive disconnections.
381:      *
382:      * @param nodeId The id of the node
383:      */
384:     @Override
385:     public void disconnect(String nodeId) {
386:         if (connectionStates.isDisconnected(nodeId)) {
387:             log.debug("Client requested disconnect from node {}, which is already disconnected", nodeId);
388:             return;
389:         }
390: 
391:         log.info("Client requested disconnect from node {}", nodeId);
392:         selector.close(nodeId);
